fn test_memory_type_display_fromstr_roundtrip() {
        for mt in &[MemoryType::Structural, MemoryType::Decisional, MemoryType::Episodic,
                     MemoryType::Analytical, MemoryType::Procedural] {
            let s = mt.to_string();
            let back: MemoryType = s.parse().unwrap();
            assert_eq!(*mt, back);
        }
    }
